import java.util.Scanner;

public class Main {
 public static void main(String[] args) {
 Scanner in = new Scanner(System.in);
 System.out.print("Введи любую цифру: ");
 int num = in.nextInt();
 System.out.printf("Ваша цифра: %d \n", num);
 }
}

int x = 10;
System.out.println(x); // 10
x = 25;
System.out.println(x); // 25

int oxygenLevel = 30; // Уровень кислорода в %

if (oxygenLevel > 20) {
 System.out.println("Кислорода хватит для выхода в открытый космос!");
} else {
 System.out.println("Осторожно! Кислорода мало. Остаёмся на корабле.");
}

int planetCode = 3; // Код выбранной планеты

switch (planetCode) {
 case 1:
 System.out.println("Курс на Меркурий!");
 break;
 case 2:
 System.out.println("Летим к Венере!");
 break;
 case 3:
 System.out.println("Активируем двигатели — цель: Земля!");
 break;
 case 4:
 System.out.println("Держим путь к Марсу!");
 break;
 default:
 System.out.println("Ошибка! Такой планеты в базе данных нет.");
}

System.out.println("Начинаем обратный отсчёт для запуска!");

for (int i = 10; i > 0; i--) {
 System.out.println(i + " секунд до старта!");
}

System.out.println("ПУСК! Двигатели запущены!");

int oxygenLevel = 100; // Начальный уровень кислорода

while (oxygenLevel > 15) {
 System.out.println("Кислорода достаточно: " + oxygenLevel + "% — можно работать.");
 oxygenLevel -= 10; // Каждый шаг тратим 10% кислорода
}

System.out.println("ВНИМАНИЕ! Кислорода осталось " + oxygenLevel + "%. Возвращаемся на станцию!");

boolean dangerDetected = true; // Датчики сразу показывают опасность
int sampleCount = 0;

do {
 sampleCount++;
 System.out.println("Взята проба грунта №" + sampleCount);

 // Робот решает, есть ли опасность
 if (sampleCount >= 3) {
 dangerDetected = false; // После 3 проб опасность устранена
 }
} while (dangerDetected);

System.out.println("Сбор проб завершён. Всего взято: " + sampleCount + " проб.");

