// Создаем двумерный массив 5x5
int[][] array = new int[5][5];

// Заполняем массив числами, введенными пользователем
System.out.println("Введите 25 чисел для заполнения массива (по 5 чисел в каждой строке):");
for (int i = 0; i < array.length; i++) {
 for (int j = 0; j < array[i].length; j++) {
 System.out.print("Введите число для элемента [" + i + "][" + j + "]: ");
 array[i][j] = scanner.nextInt(); // Считываем число с клавиатуры
 }
}

// Заполняем массив квадратами от 0
int k = 0;
for (int i = 0; i < array.length; i++) {
 for (int j = 0; j < array[i].length; j++) {
 array[i][j] = k * k;
 k++;
 }
}

// Создаем объект Random для генерации случайных чисел
Random random = new Random();

// Заполняем массив случайными числами от 0 до 99
for (int i = 0; i < array.length; i++) {
 for (int j = 0; j < array[i].length; j++) {
 array[i][j] = random.nextInt(100); // Случайное число от 0 до 99
 }
}

// Выводим элементы массива
System.out.println("Элементы двумерного массива:");
for (int i = 0; i < array.length; i++) {
 for (int j = 0; j < array[i].length; j++) {
 System.out.print(array[i][j] + "\t"); // Выводим элементы с табуляцией
 }
 System.out.println(); // Переход на новую строку после каждой строки массива
}

int[][] tArray = {{5,7,3,17}, {7,0,1,12}, {8,1,2,3}};

for (int i = 0; i < 3; i++) { // идём по строкам
 for (int j = 0; j < 4; j++) { // идём по столбцам
 System.out.print(" " + tArray[i][j] + " "); // вывод элемента
 }
 System.out.println(); // перенос строки ради визуального сохранения табличной формы
}

